class Solution:
    def maxWalls(self, robots, distance, walls):
        n = len(robots)
        pairs = sorted(zip(robots, distance))
        robpos = [p for p, _ in pairs]
        wallset = set(walls)
        best = 0
        for mask in range(1 << n):
            destroyed = set()
            for i, (p, d) in enumerate(pairs):
                if (mask >> i) & 1:
                    j = i + 1
                    for w in walls:
                        if p + 1 <= w <= p + d and (j >= n or w < robpos[j]):
                            destroyed.add(w)
                else:
                    j = i - 1
                    for w in walls:
                        if p - d <= w <= p - 1 and (j < 0 or w > robpos[j]):
                            destroyed.add(w)
            for p, _ in pairs:
                if p in wallset:
                    destroyed.add(p)
            if len(destroyed) > best:
                best = len(destroyed)
        return best

