import bisect
class Solution:
    def maxWalls(self, robots, distance, walls):
        n = len(robots)
        pairs = sorted(zip(robots, distance))
        pos = [p for p, _ in pairs]
        dist = [d for _, d in pairs]
        W = sorted(walls)
        base = 0
        for p in pos:
            k = bisect.bisect_left(W, p)
            if k < len(W) and W[k] == p:
                base += 1
        def gap_union(il, ir, lfr, rfl):
            lo = pos[il] + 1
            hi = pos[ir] - 1
            if lo > hi:
                return 0
            L = bisect.bisect_left(W, lo)
            R = bisect.bisect_right(W, hi)
            rl = pos[il] + dist[il]
            ll = pos[ir] - dist[ir]
            cnt = 0
            for w in W[L:R]:
                if (lfr and w <= rl) or (rfl and w >= ll):
                    cnt += 1
            return cnt
        def left_end(rfl):
            if not rfl:
                return 0
            hi = pos[0] - 1
            ll = pos[0] - dist[0]
            return bisect.bisect_right(W, hi) - bisect.bisect_left(W, ll)
        def right_end(lfr):
            if not lfr:
                return 0
            lo = pos[n - 1] + 1
            rl = pos[n - 1] + dist[n - 1]
            return bisect.bisect_right(W, rl) - bisect.bisect_left(W, lo)
        NEG = -1
        dp = [[NEG, NEG] for _ in range(n)]
        for d in (0, 1):
            v = left_end(True) if d == 0 else 0
            dp[0][d] = v
        for i in range(1, n):
            for d in (0, 1):
                best = NEG
                for pd in (0, 1):
                    if dp[i - 1][pd] == NEG:
                        continue
                    g = gap_union(i - 1, i, pd == 1, d == 0)
                    cand = dp[i - 1][pd] + g
                    if cand > best:
                        best = cand
                dp[i][d] = best
        ans = 0
        for d in (0, 1):
            if dp[n - 1][d] == NEG:
                continue
            v = dp[n - 1][d] + (right_end(True) if d == 1 else 0)
            if v > ans:
                ans = v
        return ans + base

