var maxWalls = function(robots, distance, walls) {
    const n = robots.length;
    const pairs = robots.map((p, i) => [p, distance[i]]).sort((a, b) => a[0] - b[0]);
    const pos = pairs.map(p => p[0]);
    const dist = pairs.map(p => p[1]);
    const W = walls.slice().sort((a, b) => a - b);
    let base = 0;
    for (const p of pos) {
        const k = lowerBound(W, p);
        if (k < W.length && W[k] === p) base++;
    }
    function gapUnion(il, ir, lfr, rfl) {
        const lo = pos[il] + 1, hi = pos[ir] - 1;
        if (lo > hi) return 0;
        const L = lowerBound(W, lo), R = upperBound(W, hi);
        const rl = pos[il] + dist[il];
        const ll = pos[ir] - dist[ir];
        let cnt = 0;
        for (let t = L; t < R; t++) {
            const w = W[t];
            if ((lfr && w <= rl) || (rfl && w >= ll)) cnt++;
        }
        return cnt;
    }
    function leftEnd(rfl) {
        if (!rfl) return 0;
        const hi = pos[0] - 1;
        const ll = pos[0] - dist[0];
        return upperBound(W, hi) - lowerBound(W, ll);
    }
    function rightEnd(lfr) {
        if (!lfr) return 0;
        const lo = pos[n - 1] + 1;
        const rl = pos[n - 1] + dist[n - 1];
        return upperBound(W, rl) - lowerBound(W, lo);
    }
    const NEG = -1;
    const dp = Array.from({length: n}, () => [NEG, NEG]);
    for (let d = 0; d < 2; d++) dp[0][d] = (d === 0) ? leftEnd(true) : 0;
    for (let i = 1; i < n; i++) {
        for (let d = 0; d < 2; d++) {
            let best = NEG;
            for (let pd = 0; pd < 2; pd++) {
                if (dp[i - 1][pd] === NEG) continue;
                const g = gapUnion(i - 1, i, pd === 1, d === 0);
                const cand = dp[i - 1][pd] + g;
                if (cand > best) best = cand;
            }
            dp[i][d] = best;
        }
    }
    let ans = 0;
    for (let d = 0; d < 2; d++) {
        if (dp[n - 1][d] === NEG) continue;
        const v = dp[n - 1][d] + ((d === 1) ? rightEnd(true) : 0);
        if (v > ans) ans = v;
    }
    return ans + base;
};
